details.publicGo:
func largeOddNum(s string) string {
    //your code goes here
    n := len(s)
    for i := n - 1; i >= 0; i-- {
        digit := s[i] - '0'
        if digit%2 == 1 {
            res := s[:i+1]

            firstNonZero := 0
            for firstNonZero < len(res)-1 && res[firstNonZero] == '0' {
                firstNonZero++
            }
            return res[firstNonZero:]
        }
    }
    return ""
}

