details.publicCsharp:
/*Definition for singly Linked List
public class ListNode
{
    public int val;
    public ListNode next;
    public ListNode child;

    public ListNode()
    {
        val = 0;
        next = null;
        child = null;
    }

    public ListNode(int data1)
    {
        val = data1;
        next = null;
        child = null;
    }

    public ListNode(int data1, ListNode next1, ListNode next2)
    {
        val = data1;
        next = next1;
        child = next2;
    }
}*/
public class Solution
{
    public ListNode FlattenLinkedList(ListNode head)
    {
        if (head == null)
        {
            return null;
        }

        List<int> values = new List<int>();
        ListNode current = head;
        while (current != null)
        {
            ListNode child = current;
            while (child != null)
            {
                values.Add(child.val);
                child = child.child;
            }
            current = current.next;
        }

        values.Sort();

        ListNode newHead = null;
        ListNode tail = null;
        foreach (int val in values)
        {
            ListNode newNode = new ListNode(val);
            if (newHead == null)
            {
                newHead = newNode;
                tail = newNode;
            }
            else
            {
                tail.child = newNode;
                tail = newNode;
            }
        }

        return newHead;
    }
}

