details.publicCsharp:
public class Solution {
    public string shortestCommonSupersequence(string str1, string str2) {
        // Your code goes here
        // This is a common dynamic programming approach
        // Find the length of the Longest Common Subsequence (LCS) first

        int n = str1.Length;
        int m = str2.Length;

        // dp[i,j] stores the length of LCS of str1[0..i-1] and str2[0..j-1]
        int[,] dp = new int[n + 1, m + 1];

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                if (i == 0 || j == 0) {
                    dp[i, j] = 0;
                } else if (str1[i - 1] == str2[j - 1]) {
                    dp[i, j] = 1 + dp[i - 1, j - 1];
                } else {
                    dp[i, j] = Math.Max(dp[i - 1, j], dp[i, j - 1]);
                }
            }
        }

        // Reconstruct the Shortest Common Supersequence (SCS)
        // We build the string backwards from the DP table

        int i_scs = n;
        int j_scs = m;
        System.Text.StringBuilder result = new System.Text.StringBuilder();

        while (i_scs > 0 && j_scs > 0) {
            if (str1[i_scs - 1] == str2[j_scs - 1]) {
                // If characters match, they are part of LCS and SCS. Append one and move diagonally.
                result.Append(str1[i_scs - 1]);
                i_scs--;
                j_scs--;
            } else if (dp[i_scs - 1, j_scs] > dp[i_scs, j_scs - 1]) {
                // If dp[i-1][j] is greater, it means str1[i-1] was not included in the LCS path
                // from str2[0..j-1]. So, str1[i-1] must be included in SCS.
                result.Append(str1[i_scs - 1]);
                i_scs--;
            } else {
                 // If dp[i][j-1] is greater or equal, str2[j-1] was not included in LCS path
                 // from str1[0..i-1]. Include str2[j-1] in SCS.
                result.Append(str2[j_scs - 1]);
                j_scs--;
            }
        }

        // Append any remaining characters from str1 or str2
        // These are characters not part of the LCS that haven't been added yet

        while (i_scs > 0) {
            result.Append(str1[i_scs - 1]);
            i_scs--;
        }

        while (j_scs > 0) {
            result.Append(str2[j_scs - 1]);
            j_scs--;
        }

        // The string was built backwards during reconstruction, reverse it
        char[] resultArray = result.ToString().ToCharArray();
        Array.Reverse(resultArray); // Use Array.Reverse on the char array
        return new string(resultArray); // Convert the char array back to a string
    }
}

